package policy

import (
	"bytes"
	"context"
	"encoding/json"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	policyTypes "github.com/cilium/cilium/pkg/policy/types"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	pal := NewPolicyAuditLogger(logrus.InfoLevel, nil)
	require.NotNil(t, pal)
	assert.Equal(t, logrus.InfoLevel, pal.level)
	assert.Nil(t, pal.output)
	assert.Nil(t, pal.logger)
}

func TestNewPolicyAuditLoggerWithOutput(t *testing.T) {
	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.DebugLevel, &buf)
	require.NotNil(t, pal)
	assert.NotNil(t, pal.logger)
}

func TestLogDecision(t *testing.T) {
	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.InfoLevel, &buf)

	pal.LogDecision(identity.NumericIdentity(1234), "test-policy", VerdictAllow, "matched allow rule")

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)

	assert.Equal(t, "policy decision", entry["msg"])
	assert.Equal(t, "allow", entry["verdict"])
	assert.Equal(t, "test-policy", entry["policyName"])
	assert.Equal(t, "matched allow rule", entry["reason"])
}

func TestLogDecisionDeny(t *testing.T) {
	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.InfoLevel, &buf)

	pal.LogDecision(identity.NumericIdentity(5678), "deny-policy", VerdictDeny, "no matching allow rule")

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)

	assert.Equal(t, "policy decision", entry["msg"])
	assert.Equal(t, "deny", entry["verdict"])
}

func TestLogEvaluation(t *testing.T) {
	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.InfoLevel, &buf)

	key := policyTypes.Key{
		Identity: 42,
		DestPort: 80,
	}
	ctx := context.Background()

	pal.LogEvaluation(ctx, key, nil, true)

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)

	assert.Equal(t, "policy evaluation", entry["msg"])
	assert.Equal(t, "allow", entry["verdict"])
}

func TestLogEvaluationDeny(t *testing.T) {
	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.InfoLevel, &buf)

	key := policyTypes.Key{
		Identity: 99,
	}
	ctx := context.Background()

	pal.LogEvaluation(ctx, key, nil, false)

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)

	assert.Equal(t, "deny", entry["verdict"])
}

func TestLogDecisionNilOutput(t *testing.T) {
	// Should not panic when no output is set.
	pal := NewPolicyAuditLogger(logrus.DebugLevel, nil)
	pal.LogDecision(identity.NumericIdentity(1), "p", VerdictAllow, "r")
}

func TestLogEvaluationNilOutput(t *testing.T) {
	pal := NewPolicyAuditLogger(logrus.DebugLevel, nil)
	key := policyTypes.Key{}
	pal.LogEvaluation(context.Background(), key, nil, true)
}

func TestPolicyVerdicts(t *testing.T) {
	assert.Equal(t, PolicyVerdict("allow"), VerdictAllow)
	assert.Equal(t, PolicyVerdict("deny"), VerdictDeny)
}

