	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
	policyTypes "github.com/cilium/cilium/pkg/policy/types"
)

// PolicyVerdict represents the result of a policy evaluation.
type PolicyVerdict string

const (
	// VerdictAllow indicates traffic is allowed.
	VerdictAllow PolicyVerdict = "allow"
	// VerdictDeny indicates traffic is denied.
	VerdictDeny PolicyVerdict = "deny"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes. It integrates with Cilium's existing
// logging framework and supports JSON-structured output.
type PolicyAuditLogger struct {
	lock.Mutex

	// level is the logrus log level for audit messages.
	level logrus.Level
	// output is the writer for audit log messages; if nil the package-level log is used.
	output io.Writer
	// logger is an optional dedicated logrus.Logger for audit output.
	logger *logrus.Logger
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger at the given log level.
// If output is non-nil, a dedicated JSON-formatted logger writing to output is used.
func NewPolicyAuditLogger(level logrus.Level, output io.Writer) *PolicyAuditLogger {
	pal := &PolicyAuditLogger{
		level:  level,
		output: output,
	}
	if output != nil {
		l := logrus.New()
		l.SetOutput(output)
		l.SetFormatter(&logrus.JSONFormatter{})
		l.SetLevel(level)
		pal.logger = l
	}
	return pal
}

// LogDecision logs a policy decision with identity, policy name, verdict, and reason.
func (pal *PolicyAuditLogger) LogDecision(id identity.NumericIdentity, policyName string, verdict PolicyVerdict, reason string) {
	pal.Lock()
	defer pal.Unlock()

	fields := logrus.Fields{
		logfields.Identity: id,
		"policyName":       policyName,
		"verdict":          string(verdict),
		"reason":           reason,
	}

	if pal.logger != nil {
		pal.logger.WithFields(fields).Log(pal.level, "policy decision")
		return
	}

	scopedLog := log.WithFields(fields)
	scopedLog.Log(pal.level, "policy decision")
}

// LogEvaluation logs a policy evaluation result for a given policy key and selector cache.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey policyTypes.Key, sc *SelectorCache, result bool) {
	pal.Lock()
	defer pal.Unlock()

	verdict := VerdictDeny
	if result {
		verdict = VerdictAllow
	}

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
		"verdict":           string(verdict),
	}

	if sc != nil {
		fields["selectorCacheModel"] = sc.GetModel()
	}

	if pal.logger != nil {
		pal.logger.WithFields(fields).Log(pal.level, "policy evaluation")
		return
	}

	scopedLog := log.WithFields(fields)
	scopedLog.Log(pal.level, "policy evaluation")
}

