	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.DebugLevel, &buf)
	require.NotNil(t, pal)
	assert.NotNil(t, pal.logger)
}

func TestLogDecision(t *testing.T) {
	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.InfoLevel, &buf)

	pal.LogDecision(identity.NumericIdentity(1234), "test-policy", VerdictAllow, "matched allow rule")

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)

	assert.Equal(t, "policy decision", entry["msg"])
	assert.Equal(t, "allow", entry["verdict"])
	assert.Equal(t, "test-policy", entry["policyName"])
	assert.Equal(t, "matched allow rule", entry["reason"])
}

func TestLogDecisionDeny(t *testing.T) {
	var buf bytes.Buffer
	pal := NewPolicyAuditLogger(logrus.InfoLevel, &buf)

	pal.LogDecision(identity.NumericIdentity(5678), "deny-policy", VerdictDeny, "no matching allow rule")

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)

	assert.Equal(t, "policy decision", entry["msg"])
	assert.Equal(t, "deny", entry["verdict"])
}

